import{_ as t,H as n,f as s,i as e}from"./chunks/framework.eFU6Tutu.js";const g=JSON.parse('{"title":"invnz 是什么","description":"","frontmatter":{},"headers":[],"relativePath":"guide/what-is-invnz.md","filePath":"guide/what-is-invnz.md"}'),i={name:"guide/what-is-invnz.md"};function o(d,a,r,l,p,h){return n(),s("div",null,[...a[0]||(a[0]=[e(`<h1 id="invnz-是什么" tabindex="-1">invnz 是什么 <a class="header-anchor" href="#invnz-是什么" aria-label="Permalink to &quot;invnz 是什么&quot;">​</a></h1><p><strong>invnz</strong> 是一个将汉语拼音转换为「音韵字」的工具——把拼音的每一个音素映射为一个汉字部件，再用汉字的结构规则组合起来。</p><p>结果是一个<strong>看起来像汉字、实际上表达拼音</strong>的字符。</p><h2 id="为什么需要它" tabindex="-1">为什么需要它？ <a class="header-anchor" href="#为什么需要它" aria-label="Permalink to &quot;为什么需要它？&quot;">​</a></h2><p>拼音用拉丁字母记录汉语发音。但字母是线性的——<code>zhong</code> 只是 5 个字母的排列，我们看不到声母在哪里结束、韵母从哪里开始。</p><p>汉字则不同。汉字是<strong>结构化的</strong>——上下、左右、包围，每一种结构都传递着信息。</p><p>invnz 把拼音的结构<strong>可视化</strong>出来：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>zhong（5 个字母，线性排列）</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>⿱止工（3 个部件，结构清晰）</span></span>
<span class="line"><span> ├─ 止（声母 zh）</span></span>
<span class="line"><span> └─ 工（韵母 ong）</span></span></code></pre></div><h2 id="它是怎么工作的" tabindex="-1">它是怎么工作的？ <a class="header-anchor" href="#它是怎么工作的" aria-label="Permalink to &quot;它是怎么工作的？&quot;">​</a></h2><p>invnz 的工作方式可以概括为三步：</p><h3 id="_1-拆解音素" tabindex="-1">1. 拆解音素 <a class="header-anchor" href="#_1-拆解音素" aria-label="Permalink to &quot;1. 拆解音素&quot;">​</a></h3><p>把拼音拆成最小的发音单位——<strong>音素（phoneme）</strong>。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>zhong → zh + ong</span></span>
<span class="line"><span>tian  → t + ie + an</span></span>
<span class="line"><span>shuang → sh + u + ang</span></span></code></pre></div><h3 id="_2-映射字根" tabindex="-1">2. 映射字根 <a class="header-anchor" href="#_2-映射字根" aria-label="Permalink to &quot;2. 映射字根&quot;">​</a></h3><p>每个音素对应一个汉字部件（称为<strong>字根</strong>）：</p><table tabindex="0"><thead><tr><th>音素</th><th>字根</th><th>说明</th></tr></thead><tbody><tr><td><code>zh</code></td><td>止</td><td>声母 zh 的象形</td></tr><tr><td><code>t</code></td><td>七</td><td>声母 t 的象形</td></tr><tr><td><code>ie</code></td><td>也</td><td>韵母 ie 的字根</td></tr><tr><td><code>an</code></td><td>𰃦</td><td>韵尾 an 的包围形</td></tr><tr><td><code>ong</code></td><td>工</td><td>韵母 ong 的字根</td></tr></tbody></table><h3 id="_3-组合成形" tabindex="-1">3. 组合成形 <a class="header-anchor" href="#_3-组合成形" aria-label="Permalink to &quot;3. 组合成形&quot;">​</a></h3><p>用汉字结构指示符（IDC）将字根组合起来：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>止（上下结构） → ⿱止</span></span>
<span class="line"><span>工              → 工</span></span>
<span class="line"><span>⿱止 + 工       → ⿱止工</span></span></code></pre></div><h2 id="它不是什么" tabindex="-1">它不是什么？ <a class="header-anchor" href="#它不是什么" aria-label="Permalink to &quot;它不是什么？&quot;">​</a></h2><ul><li><strong>不是新的拼音方案</strong> — 它不改变读音，只是把读音可视化</li><li><strong>不是一个字体</strong> — 它输出的是 IDS 字符串，不是渲染好的字形</li><li><strong>不是翻译工具</strong> — 它不翻译汉字，只编码拼音</li></ul><h2 id="它能做什么" tabindex="-1">它能做什么？ <a class="header-anchor" href="#它能做什么" aria-label="Permalink to &quot;它能做什么？&quot;">​</a></h2><ul><li><strong>教育</strong>：帮助学习者理解拼音的声韵结构</li><li><strong>设计</strong>：作为一种视觉元素，把拼音变成图形</li><li><strong>研究</strong>：探索汉语音韵与汉字结构的对应关系</li></ul><hr><p>继续阅读<a href="/guide/how-it-works.html">内部原理</a>，深入了解音素拆解和字根组合的完整过程。</p>`,25)])])}const u=t(i,[["render",o]]);export{g as __pageData,u as default};
